if (!defined('ABSPATH')) {
    exit;
}

class Membership_User_File_Uploads {
    private $option_key = 'mufu_allowed_mimes';
    private $meta_key = '_mufu_user_files';

    public function __construct() {
        add_shortcode('user_file_upload_form', array($this, 'render_upload_form'));
        add_action('init', array($this, 'handle_upload'));
        add_action('show_user_profile', array($this, 'render_user_files_admin'));
        add_action('edit_user_profile', array($this, 'render_user_files_admin'));
        add_action('wp_enqueue_scripts', array($this, 'enqueue_styles'));
        register_activation_hook(__FILE__, array($this, 'activate'));
    }

    public function activate() {
        $upload = wp_upload_dir();
        $dir = trailingslashit($upload['basedir']) . 'user-files/';
        if (!file_exists($dir)) {
            wp_mkdir_p($dir);
        }

        if (!get_option($this->option_key)) {
            update_option($this->option_key, array(
                'jpg|jpeg|jpe' => 'image/jpeg',
                'gif'          => 'image/gif',
                'png'          => 'image/png',
                'webp'         => 'image/webp',
                'pdf'          => 'application/pdf',
                'doc'          => 'application/msword',
                'docx'         => 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
                'txt'          => 'text/plain',
                'rtf'          => 'application/rtf',
            ));
        }
    }

    public function enqueue_styles() {
        $css = '
        .mufu-wrap{max-width:700px;margin:20px 0;padding:20px;border:1px solid #ddd;background:#fff}
        .mufu-wrap label{display:block;margin-bottom:8px;font-weight:600}
        .mufu-wrap input[type="file"]{display:block;margin-bottom:12px}
        .mufu-wrap input[type="text"]{width:100%;max-width:400px;margin-bottom:12px}
        .mufu-message{padding:10px 12px;margin-bottom:15px;border-radius:4px}
        .mufu-success{background:#ecf7ed;color:#1e6b2a;border:1px solid #b7dfbd}
        .mufu-error{background:#fdecec;color:#8a1f11;border:1px solid #f5c2c0}
        .mufu-files{margin-top:20px}
        .mufu-files ul{margin:0;padding-left:18px}
        .mufu-files img{max-width:120px;height:auto;display:block;margin-top:8px}
        ';
        wp_register_style('mufu-inline-style', false);
        wp_enqueue_style('mufu-inline-style');
        wp_add_inline_style('mufu-inline-style', $css);
    }

    public function render_upload_form() {
        if (!is_user_logged_in()) {
            return '<div class="mufu-wrap">You must be logged in to upload files.</div>';
        }

        $message = '';
        if (isset($_GET['mufu_status'])) {
            if ($_GET['mufu_status'] === 'success') {
                $message = '<div class="mufu-message mufu-success">File uploaded successfully.</div>';
            } elseif ($_GET['mufu_status'] === 'error' && !empty($_GET['mufu_msg'])) {
                $message = '<div class="mufu-message mufu-error">' . esc_html(wp_unslash($_GET['mufu_msg'])) . '</div>';
            }
        }

        $user_id = get_current_user_id();
        $files = get_user_meta($user_id, $this->meta_key, true);
        if (!is_array($files)) {
            $files = array();
        }

        ob_start();
        echo '<div class="mufu-wrap">';
        echo $message;
        echo '<form method="post" enctype="multipart/form-data">';
        wp_nonce_field('mufu_upload_action', 'mufu_nonce');
        echo '<label for="mufu_file_label">File Label (optional)</label>';
        echo '<input type="text" name="mufu_file_label" id="mufu_file_label" maxlength="190" />';
        echo '<label for="mufu_user_file">Choose File</label>';
        echo '<input type="file" name="mufu_user_file" id="mufu_user_file" required />';
        echo '<input type="hidden" name="mufu_upload_submit" value="1" />';
        echo '<button type="submit">Upload File</button>';
        echo '</form>';

        echo '<div class="mufu-files">';
        echo '<h3>Your Uploaded Files</h3>';
        if (!empty($files)) {
            echo '<ul>';
            foreach ($files as $file) {
                $url = isset($file['url']) ? $file['url'] : '';
                $label = !empty($file['label']) ? $file['label'] : basename($url);
                $type = isset($file['type']) ? $file['type'] : '';
                echo '<li>';
                echo '<a href="' . esc_url($url) . '" target="_blank" rel="noopener noreferrer">' . esc_html($label) . '</a>';
                if (strpos($type, 'image/') === 0) {
                    echo '<img src="' . esc_url($url) . '" alt="' . esc_attr($label) . '" />';
                }
                echo '</li>';
            }
            echo '</ul>';
        } else {
            echo '<p>No files uploaded yet.</p>';
        }
        echo '</div>';
        echo '</div>';

        return ob_get_clean();
    }

    public function handle_upload() {
        if (!isset($_POST['mufu_upload_submit'])) {
            return;
        }

        if (!is_user_logged_in()) {
            $this->redirect_with_message('error', 'You must be logged in.');
        }

        if (!isset($_POST['mufu_nonce']) || !wp_verify_nonce(sanitize_text_field(wp_unslash($_POST['mufu_nonce'])), 'mufu_upload_action')) {
            $this->redirect_with_message('error', 'Security check failed.');
        }

        if (!isset($_FILES['mufu_user_file']) || empty($_FILES['mufu_user_file']['name'])) {
            $this->redirect_with_message('error', 'No file selected.');
        }

        $file = $_FILES['mufu_user_file'];

        if (!empty($file['error'])) {
            $this->redirect_with_message('error', 'Upload error code: ' . intval($file['error']));
        }

        $allowed_mimes = get_option($this->option_key, array());
        $original_name = isset($file['name']) ? sanitize_file_name(wp_unslash($file['name'])) : '';
        $tmp_name = isset($file['tmp_name']) ? $file['tmp_name'] : '';

        $check = wp_check_filetype_and_ext($tmp_name, $original_name, $allowed_mimes);
        $ext = !empty($check['ext']) ? $check['ext'] : '';
        $type = !empty($check['type']) ? $check['type'] : '';

        if (empty($ext) || empty($type)) {
            $fallback = wp_check_filetype($original_name, $allowed_mimes);
            $ext = !empty($fallback['ext']) ? $fallback['ext'] : '';
            $type = !empty($fallback['type']) ? $fallback['type'] : '';
        }

        if (empty($ext) || empty($type)) {
            $this->redirect_with_message('error', 'File type not allowed.');
        }

        if (!is_uploaded_file($tmp_name)) {
            $this->redirect_with_message('error', 'Invalid uploaded file.');
        }

        $upload = wp_upload_dir();
        $base_dir = trailingslashit($upload['basedir']) . 'user-files/';
        $base_url = trailingslashit($upload['baseurl']) . 'user-files/';

        if (!file_exists($base_dir)) {
            wp_mkdir_p($base_dir);
        }

        if (!file_exists($base_dir) || !is_dir($base_dir) || !is_writable($base_dir)) {
            $this->redirect_with_message('error', 'Upload directory is not writable.');
        }

        $user_id = get_current_user_id();
        $safe_name = wp_unique_filename($base_dir, $user_id . '-' . time() . '-' . $original_name);
        $destination = $base_dir . $safe_name;

        if (!move_uploaded_file($tmp_name, $destination)) {
            $this->redirect_with_message('error', 'Could not save uploaded file.');
        }

        @chmod($destination, 0644);

        $label = '';
        if (isset($_POST['mufu_file_label'])) {
            $label = sanitize_text_field(wp_unslash($_POST['mufu_file_label']));
        }

        $files = get_user_meta($user_id, $this->meta_key, true);
        if (!is_array($files)) {
            $files = array();
        }

        $files[] = array(
            'label'      => $label,
            'file_name'  => $safe_name,
            'original'   => $original_name,
            'path'       => $destination,
            'url'        => $base_url . $safe_name,
            'type'       => $type,
            'uploaded'   => current_time('mysql'),
        );

        update_user_meta($user_id, $this->meta_key, $files);

        $this->redirect_with_message('success', '');
    }

    private function redirect_with_message($status, $msg) {
        $redirect = wp_get_referer();
        if (!$redirect) {
            $redirect = home_url('/');
        }

        $redirect = add_query_arg('mufu_status', rawurlencode($status), $redirect);
        if (!empty($msg)) {
            $redirect = add_query_arg('mufu_msg', rawurlencode($msg), $redirect);
        }

        wp_safe_redirect($redirect);
        exit;
    }

    public function render_user_files_admin($user) {
        if (!current_user_can('edit_user', $user->ID)) {
            return;
        }

        $files = get_user_meta($user->ID, $this->meta_key, true);
        if (!is_array($files)) {
            $files = array();
        }

        echo '<h2>User Uploaded Files</h2>';
        if (empty($files)) {
            echo '<p>No files uploaded.</p>';
            return;
        }

        echo '<table class="form-table"><tbody>';
        foreach ($files as $file) {
            $label = !empty($file['label']) ? $file['label'] : (!empty($file['original']) ? $file['original'] : 'File');
            $url = !empty($file['url']) ? $file['url'] : '';
            $type = !empty($file['type']) ? $file['type'] : '';
            $uploaded = !empty($file['uploaded']) ? $file['uploaded'] : '';
            echo '<tr>';
            echo '<th>' . esc_html($label) . '</th>';
            echo '<td>';
            echo '<a href="' . esc_url($url) . '" target="_blank" rel="noopener noreferrer">View File</a>';
            if ($uploaded) {
                echo '<br><span>' . esc_html($uploaded) . '</span>';
            }
            if (strpos($type, 'image/') === 0) {
                echo '<br><img src="' . esc_url($url) . '" alt="' . esc_attr($label) . '" style="max-width:150px;height:auto;margin-top:8px;" />';
            }
            echo '</td>';
            echo '</tr>';
        }
        echo '</tbody></table>';
    }
}

new Membership_User_File_Uploads();